    final int len = str.length();
    // Check for empty string or length greater than 10
    if (len == 0 || len > 10) {
        return -1;
    }

    // Check for leading zeros (except for the single digit '0')
    if (len > 1 && str.charAt(0) == '0') {
        return -1;
    }

    // Check for valid characters (digits only)
    for (int i = 0; i < len; ++i) {
        char c = str.charAt(i);
        if (c > '9' || c < '0') {
            return -1;
        }
    }

    // Check if the length is 10 and the parsed long exceeds the integer limit
    if (len == 10) {
        long l = NumberInput.parseLong(str);
        if (l > Integer.MAX_VALUE) {
            return -1;
        }
    }

    // Return the parsed integer value
    return NumberInput.parseInt(str);
}
```

